1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<[number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const SURVIVAL_NEIGHBOR_COUNTS: ReadonlyArray<number> = [2, 3];
10	
11	const cellKey = (x: number, y: number): string => `${x},${y}`;
12	
13	export function nextGeneration(cells: Cell[]): Cell[] {
14	  const aliveCells = new Set(cells.map(([x, y]) => cellKey(x, y)));
15	
16	  const countLiveNeighbors = (x: number, y: number): number =>
17	    NEIGHBOR_OFFSETS.filter(([dx, dy]) => aliveCells.has(cellKey(x + dx, y + dy))).length;
18	
19	  return cells.filter(([x, y]) => SURVIVAL_NEIGHBOR_COUNTS.includes(countLiveNeighbors(x, y)));
20	}
21

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return an empty array when given an empty array", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a block (2x2) alive unchanged (still life)", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result.sort()).toEqual(block.sort());
18	  });
19	  it("should kill a live cell with more than 3 neighbors (overpopulation)", () => {
20	    // Plus shape: center (1,1) has 4 live neighbors → dies
21	    const cells: [number, number][] = [[1, 0], [0, 1], [1, 1], [2, 1], [1, 2]];
22	    const result = nextGeneration(cells);
23	    expect(result).not.toContainEqual([1, 1]);
24	  });
